import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String filename = "data.txt";

        // Assume user input is not properly sanitized and directly used in constructing the file path
        String userInput = "../evil.txt";

        // Validate user input to prevent directory traversal
        if (!userInput.contains("..") && !userInput.contains("/")) {
            File file = new File("files/" + userInput);  // Safe code

            try (FileInputStream fis = new FileInputStream(file)) {
                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }
            } catch (IOException e) {
                System.out.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path");
        }
    }
}

